  signupDate: signup.signupDate,
  welcomeEmailSent: welcomeSent,
  welcomeEmailId: resendResponse.id || null,
  dripEmailsSent: [],
  status: 'active'
};

return [{
  json: dripEntry
}];

const users = $input.first().json;

const userList = Array.isArray(users) ? users : (Array.isArray($input.all().map(i => i.json)) ? $input.all().map(i => i.json) : []);

// Statuses that should never receive drip emails
const EXCLUDED_STATUSES = ['unsubscribed', 'cancelled', 'churned', 'deleted', 'banned'];

const now = new Date();
const results = [];

for (const user of userList) {
  // Resilience gate: skip users who unsubscribed, cancelled, or churned
  if (EXCLUDED_STATUSES.includes(user.status)) continue;
  if (user.unsubscribed === true || user.unsubscribed_at) continue;
  if (user.cancelled_at) continue;

  const signupDate = new Date(user.signup_date);
  const daysSinceSignup = Math.floor((now - signupDate) / (1000 * 60 * 60 * 24));
  const sent = user.drip_emails_sent || [];

  let emailToSend = null;

  if (daysSinceSignup >= 1 && !sent.includes('day1_getting_started')) {
    emailToSend = 'day1_getting_started';
  } else if (daysSinceSignup >= 3 && !sent.includes('day3_pro_tips')) {
    emailToSend = 'day3_pro_tips';
  } else if (daysSinceSignup >= 7 && !sent.includes('day7_check_in')) {
    emailToSend = 'day7_check_in';
  } else if (daysSinceSignup >= 14 && !sent.includes('day14_upgrade') && (user.plan === 'free' || user.plan === 'starter')) {
    emailToSend = 'day14_upgrade';
  }

  if (emailToSend) {
    results.push({
      json: {
        id: user.id,
        email: user.email,
        name: user.name || 'there',
        plan: user.plan,
        businessId: user.business_id,
        daysSinceSignup,
        emailToSend,
        previouslySent: sent
      }
    });
  }
}

if (results.length === 0) {
  results.push({ json: { _skip: true } });
}

return results;

